// ═══════════════════════════════════════════════════════════════
// STRUCTURATION DES DONNÉES PAR DESTINATAIRE ET NIVEAU D'ESCALADE
// ═══════════════════════════════════════════════════════════════

const items = $input.all();

console.log('\n═══════════════════════════════════════════════════');
console.log('📊 STRUCTURATION DES NOTIFICATIONS');
console.log('═══════════════════════════════════════════════════');
console.log(`Accidents reçus: ${items.length}`);

// ─────────────────────────────────────────────────────────────
// REGROUPEMENT PAR NIVEAU D'ESCALADE ET DESTINATAIRE
// ─────────────────────────────────────────────────────────────

const notifications = {};

items.forEach(item => {
  const data = item.json;

  // Déterminer le destinataire principal selon l'escalade
  let destinatairePrincipal;
  let codeDestinataire;
  let typeDestinataire;

  if (data.niveau_escalade === 'PDG') {
    // ≤ 2 jours → PDG
    destinatairePrincipal = {
      code: data.code_pdg,
      nom: data.nom_pdg,
      prenom: data.prenom_pdg,
      email: data.email_pdg,
      telephone: data.telephone_pdg,
      chat_id: data.chat_id_pdg,
      langue: data.langue_pdg,
      bot: data.bot_pdg
    };
    codeDestinataire = data.code_pdg;
    typeDestinataire = 'PDG';
  } else if (data.niveau_escalade === 'SUPERIEUR') {
    // ≤ 3 jours → Supérieur
    destinatairePrincipal = {
      code: data.code_superieur,
      nom: data.nom_superieur,
      prenom: data.prenom_superieur,
      email: data.email_superieur,
      telephone: data.telephone_mobile_superieur,
      chat_id: data.chat_id_superieur,
      langue: data.langue_superieur,
      bot: data.bot_superieur
    };
    codeDestinataire = data.code_superieur;
    typeDestinataire = 'SUPERIEUR';
  } else {
    // ≤ 4 jours → Infirmier
    destinatairePrincipal = {
      code: data.code_salarie_infirmier,
      nom: data.nom_infirmier,
      prenom: data.prenom_infirmier,
      email: data.email_infirmier,
      telephone: data.telephone_mobile_infirmier,
      chat_id: data.chat_id_infirmier,
      langue: data.langue_infirmier,
      bot: data.bot_infirmier
    };
    codeDestinataire = data.code_salarie_infirmier;
    typeDestinataire = 'INFIRMIER';
  }

  // Créer la clé unique pour ce destinataire
  const cleDestinataire = `${typeDestinataire}_${codeDestinataire}`;

  if (!notifications[cleDestinataire]) {
    notifications[cleDestinataire] = {
      destinataire_principal: destinatairePrincipal,
      type_destinataire: typeDestinataire,
      niveau_escalade: data.niveau_escalade,

      // Infos pour les copies
      infirmier: {
        code: data.code_salarie_infirmier,
        nom: data.nom_infirmier,
        prenom: data.prenom_infirmier,
        email: data.email_infirmier,
        telephone: data.telephone_mobile_infirmier,
        chat_id: data.chat_id_infirmier,
        langue: data.langue_infirmier,
        bot: data.bot_infirmier
      },

      superieur: {
        code: data.code_superieur,
        nom: data.nom_superieur,
        prenom: data.prenom_superieur,
        email: data.email_superieur,
        telephone: data.telephone_mobile_superieur,
        chat_id: data.chat_id_superieur,
        langue: data.langue_superieur,
        bot: data.bot_superieur
      },

      accidents: []
    };
  }

  // Ajouter l'accident à la liste
  notifications[cleDestinataire].accidents.push({
    id_accident: data.id_accident,
    matricule_salarie: data.matricule_salarie,
    code_salarie: data.code_salarie,
    date_accident: data.date_accident,
    heure_accident: data.heure_accident,
    lieu_accident: data.lieu_accident,
    description_courte: data.description_courte,
    type_accident: data.type_accident,
    gravite: data.gravite,
    date_creation: data.date_creation,
    date_limite_depot: data.date_limite_depot,
    jours_depuis_creation: data.jours_depuis_creation,
    jours_restants: data.jours_restants
  });
});

// ─────────────────────────────────────────────────────────────
// CONVERSION EN TABLEAU POUR N8N
// ─────────────────────────────────────────────────────────────

const resultats = Object.values(notifications).map(notif => {
  // Statistiques
  const totalAccidents = notif.accidents.length;
  const joursMin = Math.min(...notif.accidents.map(a => a.jours_restants));
  const joursMax = Math.max(...notif.accidents.map(a => a.jours_restants));

  // Configurer les emails CC selon l'escalade
  let emailCC = [];
  let chatIDsCC = [];

  if (notif.type_destinataire === 'PDG') {
    // PDG → CC: Supérieur + Infirmier
    if (notif.superieur.email) emailCC.push(notif.superieur.email);
    if (notif.infirmier.email) emailCC.push(notif.infirmier.email);
    if (notif.superieur.chat_id) chatIDsCC.push({
      chat_id: notif.superieur.chat_id,
      bot: notif.superieur.bot,
      nom: notif.superieur.nom
    });
    if (notif.infirmier.chat_id) chatIDsCC.push({
      chat_id: notif.infirmier.chat_id,
      bot: notif.infirmier.bot,
      nom: notif.infirmier.prenom + ' ' + notif.infirmier.nom
    });
  } else if (notif.type_destinataire === 'SUPERIEUR') {
    // Supérieur → CC: Infirmier
    if (notif.infirmier.email) emailCC.push(notif.infirmier.email);
    if (notif.infirmier.chat_id) chatIDsCC.push({
      chat_id: notif.infirmier.chat_id,
      bot: notif.infirmier.bot,
      nom: notif.infirmier.prenom + ' ' + notif.infirmier.nom
    });
  }
  // Infirmier → Pas de CC

  return {
    // ─── DESTINATAIRE PRINCIPAL ───
    destinataire_principal: notif.destinataire_principal,
    type_destinataire: notif.type_destinataire,
    niveau_escalade: notif.niveau_escalade,

    // ─── COPIES ───
    email_cc: emailCC.length > 0 ? emailCC.join(',') : null,
    telegram_cc: chatIDsCC.length > 0 ? chatIDsCC : null,

    // ─── RÉFÉRENCES ───
    infirmier: notif.infirmier,
    superieur: notif.superieur,

    // ─── ACCIDENTS ───
    accidents: notif.accidents,

    // ─── STATISTIQUES ───
    statistiques: {
      total_accidents: totalAccidents,
      jours_min: joursMin,
      jours_max: joursMax,
      priorite: notif.niveau_escalade
    },

    // ─── MÉTADONNÉES ───
    meta: {
      date_traitement: new Date().toISOString(),
      langue_message: notif.destinataire_principal.langue || 'FRA',
      peut_envoyer_email: !!notif.destinataire_principal.email,
      peut_envoyer_telegram: !!notif.destinataire_principal.chat_id
    }
  };
});

// ─────────────────────────────────────────────────────────────
// RAPPORT
// ─────────────────────────────────────────────────────────────

console.log(`\nNotifications structurées: ${resultats.length}`);
console.log('Par type:');
console.log(`  - PDG: ${resultats.filter(r => r.type_destinataire === 'PDG').length}`);
console.log(`  - Supérieur: ${resultats.filter(r => r.type_destinataire === 'SUPERIEUR').length}`);
console.log(`  - Infirmier: ${resultats.filter(r => r.type_destinataire === 'INFIRMIER').length}`);
console.log('═══════════════════════════════════════════════════\n');

return resultats.map(r => ({ json: r }));

