// ─────────────────────────────────────────────────────────────
// HELPERS
// ─────────────────────────────────────────────────────────────

function formaterDate(dateStr, langue) {
  if (!dateStr) return 'N/A';
  const date = new Date(dateStr);
  const locale = langue === 'ARA' ? 'ar-MA' : langue === 'ENG' ? 'en-US' : 'fr-FR';
  return date.toLocaleDateString(locale);
}

function formaterHeure(heureStr) {
  if (!heureStr) return '';
  const h = heureStr.toString().padStart(4, '0');
  return h.substring(0, 2) + ':' + h.substring(2, 4);
}

function getEmoji(jours) {
  if (jours <= 2) return '🔴';
  if (jours <= 3) return '🟠';
  if (jours <= 4) return '🟡';
  return '🟢';
}

// ─────────────────────────────────────────────────────────────
// FONCTION DE GÉNÉRATION DE MESSAGE PRINCIPAL
// ─────────────────────────────────────────────────────────────

function genererMessagePrincipal(data) {
  const langue = data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;

  const destinataire = data.destinataire_principal;
  const stats = data.statistiques;
  const accidents = data.accidents;

  // ─── EMAIL ───
  let emailSubject = T.sujet_email[data.type_destinataire] || T.sujet_email.INFIRMIER;
  emailSubject += ` - ${stats.total_accidents} dossier(s)`;

  let emailBody = `${T.salutation} ${destinataire.prenom} ${destinataire.nom},\n\n`;
  emailBody += `${T.introduction[data.type_destinataire]}\n\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📊 ${T.section_stats}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  emailBody += `${getEmoji(stats.jours_min)} Niveau: ${data.niveau_escalade}\n`;
  emailBody += `${T.total}: ${stats.total_accidents}\n`;
  emailBody += `${T.delai_min}: ${stats.jours_min} ${T.jours}\n`;

  if (data.type_destinataire !== 'INFIRMIER') {
    emailBody += `\nInfirmier concerné: ${data.infirmier.prenom} ${data.infirmier.nom} (${data.infirmier.code})\n`;
  }

  emailBody += `\n═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📋 ${T.section_dossiers}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  accidents.forEach((acc, index) => {
    emailBody += `${index + 1}. ${getEmoji(acc.jours_restants)} ${acc.id_accident}\n`;
    emailBody += `   📅 ${T.date}: ${formaterDate(acc.date_accident, langue)} ${formaterHeure(acc.heure_accident)}\n`;
    emailBody += `   📍 ${T.lieu}: ${acc.lieu_accident || 'N/A'}\n`;
    emailBody += `   👤 Matricule: ${acc.matricule_salarie}\n`;
    emailBody += `   ⏰ ${T.delai}: ${acc.jours_restants} ${T.jours} ${T.restant} (${T.limite}: ${formaterDate(acc.date_limite_depot, langue)})\n`;
    if (acc.jours_restants <= 2) {
      emailBody += `   🚨 ${T.urgent}\n`;
    }
    emailBody += `\n`;
  });

  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  if (stats.jours_min <= 2) {
    emailBody += `🚨 ${T.action_requise}: ${T.urgent}\n`;
  }
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  emailBody += `📞 ${T.contact}:\n`;
  emailBody += `   Email: ${data.infirmier.email}\n`;
  emailBody += `   Tel: ${data.infirmier.telephone || 'N/A'}\n\n`;

  emailBody += `${T.cordialement},\n\n`;
  emailBody += `${T.signature}\n\n`;
  emailBody += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  emailBody += `🤖 ${T.message_auto} - ${formaterDate(new Date().toISOString(), langue)}\n`;
  if (data.type_destinataire === 'PDG') {
    emailBody += `🔴 Notification URGENTE envoyée au PDG\n`;
  }
  emailBody += `${T.ne_pas_repondre}\n`;

  // ─── TELEGRAM ───
  let telegramMessage = `${getEmoji(stats.jours_min)} *${T.sujet_email[data.type_destinataire]}*\n`;
  telegramMessage += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
  telegramMessage += `👤 *${destinataire.prenom} ${destinataire.nom}*\n\n`;
  telegramMessage += `📊 *${T.section_stats}*\n`;
  telegramMessage += `${T.total}: *${stats.total_accidents}*\n`;
  telegramMessage += `${T.delai_min}: *${stats.jours_min} ${T.jours}*\n\n`;


  telegramMessage += `📋 *${T.section_dossiers} ${T.not_attached} *  \n`;


  accidents.slice(0, 5).forEach((acc, index) => {
    telegramMessage += `${index + 1}. ${getEmoji(acc.jours_restants)} *${acc.id_accident}*\n`;
    telegramMessage += `   📅 ${formaterDate(acc.date_accident, langue)} ${formaterHeure(acc.heure_accident)}\n`;
    telegramMessage += `   📍 ${acc.lieu_accident || 'N/A'}\n`;
    telegramMessage += `   ⏰ ${acc.jours_restants} ${T.jours} ${T.restant}\n\n`;
  });

  if (accidents.length > 5) {
    telegramMessage += `... et ${accidents.length - 5} autre(s) dossier(s)\n\n`;
  }

  if (stats.jours_min <= 2) {
    telegramMessage += `🚨 *${T.urgent}*\n\n`;
  }



  return {
    email: {
      subject: emailSubject,
      body: emailBody
    },
    telegram: {
      text: telegramMessage,
      parse_mode: 'Markdown'
    }
  };
}

// ─────────────────────────────────────────────────────────────
// FONCTION DE GÉNÉRATION DE MESSAGE CC
// ─────────────────────────────────────────────────────────────

function genererMessageCC(data, destinataireCC, typeDestinatairePrincipal) {
  const langue = destinataireCC.langue || data.meta.langue_message || 'FRA';
  const T = TEMPLATES[langue] || TEMPLATES.FRA;

  const stats = data.statistiques;
  const accidents = data.accidents;
  const destinatairePrincipal = data.destinataire_principal;

  // Déterminer l'intro selon le contexte
  let message_envoye_a = '';
  let message_envoye_a_email = '';

  if (typeDestinatairePrincipal === 'SUPERIEUR') {
    // CC à l'infirmier depuis supérieur

    message_envoye_a = `${T.cc_message.votre_superieur} *${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}*`;
    message_envoye_a_email = `${T.cc_message.votre_superieur} ${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}`;
  } else if (typeDestinatairePrincipal === 'PDG') {
    // CC depuis PDG
    if (destinataireCC.code === data.superieur?.code) {
      // Message pour le supérieur

      message_envoye_a = `${T.cc_message.le_pdg} *${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}*`;
      message_envoye_a_email = `${T.cc_message.le_pdg} ${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}`;
    } else {
      // Message pour l'infirmier

      message_envoye_a = `${T.cc_message.le_pdg} *${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}*`;
      message_envoye_a_email = `${T.cc_message.le_pdg} ${destinatairePrincipal.prenom} ${destinatairePrincipal.nom}`;
    }
  }

  // ─── MESSAGE EMAIL CC ───
  let emailSubject = `${T.copie_info} - ${T.sujet_email[typeDestinatairePrincipal]} - ${stats.total_accidents} dossier(s)`;

  let emailBody = `${T.salutation} ${destinataireCC.prenom} ${destinataireCC.nom},\n\n`;
  emailBody += `${T.cc_message.base} ${message_envoye_a_email}.\n\n`;

  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📊 ${T.section_stats}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;
  emailBody += `${getEmoji(stats.jours_min)} Niveau: ${data.niveau_escalade}\n`;
  emailBody += `${T.total}: ${stats.total_accidents}\n`;
  emailBody += `${T.delai_min}: ${stats.jours_min} ${T.jours}\n\n`;

  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `📋 ${T.section_dossiers}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  accidents.forEach((acc, index) => {
    emailBody += `${index + 1}. ${getEmoji(acc.jours_restants)} ${acc.id_accident}\n`;
    emailBody += `   📅 ${T.date}: ${formaterDate(acc.date_accident, langue)} ${formaterHeure(acc.heure_accident)}\n`;
    emailBody += `   📍 ${T.lieu}: ${acc.lieu_accident || 'N/A'}\n`;
    emailBody += `   👤 Matricule: ${acc.matricule_salarie}\n`;
    emailBody += `   ⏰ ${T.delai}: ${acc.jours_restants} ${T.jours} ${T.restant} (${T.limite}: ${formaterDate(acc.date_limite_depot, langue)})\n`;
    if (acc.jours_restants <= 2) {
      emailBody += `   🚨 ${T.urgent}\n`;
    }
    emailBody += `\n`;
  });

  emailBody += `═══════════════════════════════════════════════════════════════\n`;
  emailBody += `${T.cc_message.action}\n`;
  emailBody += `═══════════════════════════════════════════════════════════════\n\n`;

  emailBody += `📞 ${T.contact}:\n`;
  emailBody += `   Email: ${data.infirmier.email}\n`;
  emailBody += `   Tel: ${data.infirmier.telephone || 'N/A'}\n\n`;

  emailBody += `${T.cordialement},\n\n`;
  emailBody += `${T.signature}\n\n`;
  emailBody += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  emailBody += `🤖 ${T.message_auto} - ${formaterDate(new Date().toISOString(), langue)}\n`;
  emailBody += `📋 ${T.copie_info}\n`;
  emailBody += `${T.ne_pas_repondre}\n`;

  // ─── MESSAGE TELEGRAM CC ───
  let telegramMessage = `${T.copie_info}\n`;
  telegramMessage += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
  telegramMessage += `${T.salutation} *${destinataireCC.prenom} ${destinataireCC.nom}*,\n\n`;
  telegramMessage += `${T.cc_message.base} ${message_envoye_a}.\n\n`;

  telegramMessage += `📊 *${T.section_stats}*\n`;
  telegramMessage += `${T.total}: *${stats.total_accidents}*\n`;
  telegramMessage += `${T.delai_min}: *${stats.jours_min} ${T.jours}*\n\n`;

  telegramMessage += `📋 *${T.section_dossiers} ${T.not_attached}*\n`;
  accidents.slice(0, 3).forEach((acc, index) => {
    telegramMessage += `${index + 1}. ${getEmoji(acc.jours_restants)} *${acc.id_accident}*\n`;
    telegramMessage += `   📅 ${formaterDate(acc.date_accident, langue)}\n`;
    telegramMessage += `   ⏰ ${acc.jours_restants} ${T.jours} ${T.restant}\n\n`;
  });

  if (accidents.length > 3) {
    telegramMessage += `... et ${accidents.length - 3} autre(s) dossier(s)\n\n`;
  }

  telegramMessage += `${T.cc_message.action}\n\n`;



  return {
    email: {
      subject: emailSubject,
      body: emailBody
    },
    telegram: {
      text: telegramMessage,
      parse_mode: 'Markdown'
    }
  };
}

// ─────────────────────────────────────────────────────────────
// TRAITEMENT DE TOUS LES ITEMS AVEC CC DYNAMIQUES
// ─────────────────────────────────────────────────────────────

const results = [];

inputData.forEach(item => {
  const data = item.json;
  const messagesPrincipal = genererMessagePrincipal(data);

  // ✅ Détermine les flags pour les CC
  const envoyer_cc_infirmier = (data.type_destinataire === 'SUPERIEUR' || data.type_destinataire === 'PDG');
  const envoyer_cc_superieur = (data.type_destinataire === 'PDG');

  // ═══════════════════════════════════════════════════════════
  // 1. MESSAGE PRINCIPAL
  // ═══════════════════════════════════════════════════════════
  results.push({
    json: {
      ...data,
      messages: messagesPrincipal,
      type_envoi: 'PRINCIPAL',
      destinataire_final: data.destinataire_principal,
      envoyer_cc_infirmier: envoyer_cc_infirmier,
      envoyer_cc_superieur: envoyer_cc_superieur,
      meta: {
        ...data.meta,
        langue_utilisee: data.meta.langue_message || 'FRA',
        date_generation: new Date().toISOString()
      }
    }
  });

  // ═══════════════════════════════════════════════════════════
  // 2. MESSAGES CC DYNAMIQUES
  // ═══════════════════════════════════════════════════════════

  if (data.type_destinataire === 'SUPERIEUR') {
    // 🔸 SUPERIEUR notifié → CC à INFIRMIER
    if (data.infirmier) {
      const messagesCC = genererMessageCC(data, data.infirmier, 'SUPERIEUR');

      results.push({
        json: {
          ...data,
          messages: messagesCC,
          type_envoi: 'CC',
          destinataire_final: data.infirmier,
          cc_pour_profil: 'INFIRMIER',
          envoyer_cc_infirmier: true,
          envoyer_cc_superieur: false,
          meta: {
            ...data.meta,
            langue_utilisee: data.infirmier.langue || data.meta.langue_message || 'FRA',
            date_generation: new Date().toISOString()
          }
        }
      });
    }
  } 
  else if (data.type_destinataire === 'PDG') {
    // 🔸 PDG notifié → CC à SUPERIEUR + CC à INFIRMIER

    // CC au SUPERIEUR
    if (data.superieur) {
      const messagesCCSuperieur = genererMessageCC(data, data.superieur, 'PDG');

      results.push({
        json: {
          ...data,
          messages: messagesCCSuperieur,
          type_envoi: 'CC',
          destinataire_final: data.superieur,
          cc_pour_profil: 'SUPERIEUR',
          envoyer_cc_infirmier: false,
          envoyer_cc_superieur: true,
          meta: {
            ...data.meta,
            langue_utilisee: data.superieur.langue || data.meta.langue_message || 'FRA',
            date_generation: new Date().toISOString()
          }
        }
      });
    }

    // CC à l'INFIRMIER
    if (data.infirmier) {
      const messagesCCInfirmier = genererMessageCC(data, data.infirmier, 'PDG');

      results.push({
        json: {
          ...data,
          messages: messagesCCInfirmier,
          type_envoi: 'CC',
          destinataire_final: data.infirmier,
          cc_pour_profil: 'INFIRMIER',
          envoyer_cc_infirmier: true,
          envoyer_cc_superieur: false,
          meta: {
            ...data.meta,
            langue_utilisee: data.infirmier.langue || data.meta.langue_message || 'FRA',
            date_generation: new Date().toISOString()
          }
        }
      });
    }
  }
});

// ─────────────────────────────────────────────────────────────
// RETOUR DE TOUS LES RÉSULTATS
// ─────────────────────────────────────────────────────────────

return results;
